sed -i '' -e 's/let event_bus = match/let risk_state = risk_engine::api::risk_service::RiskState::new();\n\n    if let Ok(subscriber) = risk_engine::event_bus_subscriber::EventBusSubscriber::connect(config.eventbus_url.clone(), "risk_engine_group".to_string(), uuid::Uuid::new_v4().to_string()).await {\n        if let Ok(mut rx) = subscriber.subscribe("execution.position").await {\n            let state_clone = risk_state.clone();\n            tokio::spawn(async move {\n                while let Some(event) = rx.recv().await {\n                    if let Some(payload) = event.payload {\n                        use apex_protos::events::event::Payload;\n                        match payload {\n                            Payload::PositionOpened(pos) => {\n                                let mut corr = state_clone.correlation.write().await;\n                                let _ = corr.set_correlation("Symbol", &pos.symbol, "EURUSD", rust_decimal_macros::dec!(0.5));\n                                let _ = corr.set_correlation("Symbol", &pos.symbol, "GBPUSD", rust_decimal_macros::dec!(0.4));\n                                let mut exp = state_clone.exposure.write().await;\n                                let vol = pos.initial_volume.and_then(|v| v.units.parse::<rust_decimal::Decimal>().ok()).unwrap_or_default();\n                                exp.gross_exposure += vol;\n                                if pos.side == 1 { exp.net_exposure += vol; } else { exp.net_exposure -= vol; }\n                            }\n                            Payload::PositionClosed(pos) => {\n                                let mut exp = state_clone.exposure.write().await;\n                                let vol = pos.closed_volume.and_then(|v| v.units.parse::<rust_decimal::Decimal>().ok()).unwrap_or_default();\n                                exp.gross_exposure -= vol;\n                            }\n                            _ => {}\n                        }\n                    }\n                }\n            });\n        }\n    }\n\n    let event_bus = match/' services/risk-engine-rs/src/main.rs
sed -i '' -e 's/risk_engine::api::risk_service::RiskState::new()/risk_state/' services/risk-engine-rs/src/main.rs
